def test_payroll_run_500_internal_failure_rolls_back_atomically(
    hr_admin_client, valid_2fa_otp, inject_payroll_fault, unique_period
):
    with inject_payroll_fault(period=unique_period):
        payload = {
            "period": unique_period,
            "otp": valid_2fa_otp()
        }
        resp = hr_admin_client.post("/api/payroll-runs", json=payload)
    assert resp.status_code == 500
    stubs_resp = hr_admin_client.get(
        f"/api/payroll-runs?period={unique_period}&state=completed"
    )
    assert stubs_resp.status_code == 200
    assert stubs_resp.json()["count"] == 0
    stubs_check = hr_admin_client.get(
        f"/api/pay-stubs?period={unique_period}"
    )
    assert stubs_check.status_code == 200
    assert stubs_check.json()["count"] == 0
